using System.ClientModel;
using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using OpenAI;

Console.OutputEncoding = System.Text.Encoding.UTF8;

// --- Configuration ---
var config = new ConfigurationBuilder()
    .AddJsonFile("appsettings.json", optional: true)
    .AddEnvironmentVariables()
    .Build();
var baseUrl = config["baseUrl"] ?? "https://api.openai.com/v1";
var apiKey = config["apiKey"] ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new Exception("No API key. Set OPENAI_API_KEY or configure appsettings.json");
var modelId = config["modelId"] ?? "gpt-4o-mini";

// --- IChatClient with tool support ---
var client = new OpenAIClient(new ApiKeyCredential(apiKey), new OpenAIClientOptions { Endpoint = new Uri(baseUrl) })
    .GetChatClient(modelId).AsIChatClient();

// --- Tool definitions ---
[Description("Get the current weather for a location")]
static string GetWeather([Description("City name")] string city) =>
    city.ToLower() switch {
        "london" => "London: 15°C, cloudy",
        "tokyo" => "Tokyo: 28°C, sunny",
        _ => $"{city}: 22°C, partly cloudy"
    };

[Description("Get the current date and time")]
static string GetCurrentTime() => DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");

[Description("Calculate a mathematical expression")]
static double Calculate(
    [Description("First operand")] double a,
    [Description("The operation: add, subtract, multiply, divide")] string operation,
    [Description("Second operand")] double b) =>
    operation.ToLower() switch {
        "add" => a + b, "subtract" => a - b, "multiply" => a * b, "divide" => a / b,
        _ => throw new ArgumentException($"Unknown operation: {operation}")
    };

// --- Register tools via AIFunctionFactory ---
var tools = new List<AITool>
{
    AIFunctionFactory.Create(GetWeather),
    AIFunctionFactory.Create(GetCurrentTime),
    AIFunctionFactory.Create(Calculate),
};

// --- Build pipeline: FunctionInvokingChatClient wraps the raw client ---
var chatClient = new FunctionInvokingChatClient(client);

// --- Agent setup ---
var agent = new ChatClientAgent(chatClient,
    instructions: "You are a helpful assistant. Use tools to answer questions about weather, time, and math.",
    name: "assistant",
    description: "A helpful assistant",
    tools: tools);

// --- Run queries that trigger tool use ---
var queries = new[]
{
    "What's the weather in Tokyo and London?",
    "What time is it now?",
    "Calculate 42 * 17 + 3",
};

foreach (var query in queries)
{
    Console.WriteLine($"\n>>> User: {query}");
    var response = await agent.RunAsync(query);
    Console.WriteLine($"<<< Agent: {response.Text}");
}

using System.ClientModel;
using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using OpenAI;

Console.OutputEncoding = System.Text.Encoding.UTF8;

// --- Configuration ---
var config = new ConfigurationBuilder()
    .AddJsonFile("appsettings.json", optional: true)
    .AddEnvironmentVariables()
    .Build();
var baseUrl = config["baseUrl"] ?? "https://api.openai.com/v1";
var apiKey = config["apiKey"] ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new Exception("No API key. Set OPENAI_API_KEY or configure appsettings.json");
var modelId = config["modelId"] ?? "gpt-4o-mini";

// --- IChatClient ---
var client = new OpenAIClient(new ApiKeyCredential(apiKey), new OpenAIClientOptions { Endpoint = new Uri(baseUrl) })
    .GetChatClient(modelId).AsIChatClient();

// --- Dangerous tool definition ---
[Description("Delete a file from the filesystem")]
static string DeleteFile([Description("Path to the file to delete")] string path) =>
    $"File '{path}' has been deleted successfully.";

// --- Wrap with approval requirement ---
var dangerousTool = new ApprovalRequiredAIFunction(AIFunctionFactory.Create(DeleteFile));

// --- Build pipeline with function invocation ---
var chatClient = new FunctionInvokingChatClient(client);

// --- Agent setup ---
var agent = new ChatClientAgent(chatClient,
    instructions: "You are a file management assistant. You can delete files when asked.",
    name: "file-manager",
    description: "A file management assistant",
    tools: [dangerousTool]);

// --- Interactive approval loop ---
Console.WriteLine("s05: Permission — tool approval with ApprovalRequiredAIFunction");
Console.WriteLine("The agent will ask for permission before deleting files.\n");

var query = "Please delete the file 'temp.txt' and then delete 'old_data.csv'";
Console.WriteLine($">>> User: {query}\n");

var messages = new List<ChatMessage> { new(ChatRole.User, query) };
var options = new ChatOptions { Tools = [dangerousTool] };

while (true)
{
    var response = await chatClient.GetResponseAsync(messages, options);
    messages.AddMessages(response);

    // Check for approval requests
    var approvalRequests = response.Messages
        .SelectMany(m => m.Contents)
        .OfType<FunctionCallContent>()
        .Where(fc => dangerousTool.Name.Equals(fc.Name, StringComparison.OrdinalIgnoreCase))
        .ToList();

    if (approvalRequests.Count == 0)
    {
        // No more approval requests — show final response
        Console.WriteLine($"<<< Agent: {response.Text}");
        break;
    }

    // Process each approval request
    foreach (var request in approvalRequests)
    {
        var filePath = request.Arguments?["path"]?.ToString() ?? "unknown";
        Console.Write($"[APPROVAL] Allow deletion of '{filePath}'? (y/n): ");
        var answer = Console.ReadLine()?.Trim().ToLower();

        if (answer is "y" or "yes")
        {
            // Execute the tool and return result
            var result = DeleteFile(filePath);
            Console.WriteLine($"[APPROVED] {result}");
            messages.Add(new ChatMessage(ChatRole.Tool, result));
        }
        else
        {
            // Reject the tool call
            var rejection = $"Tool call '{request.Name}' for '{filePath}' was denied by the user.";
            Console.WriteLine($"[REJECTED] {rejection}");
            messages.Add(new ChatMessage(ChatRole.Tool, rejection));
        }
    }
}

using System.ClientModel;
using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using OpenAI;

Console.OutputEncoding = System.Text.Encoding.UTF8;

// --- Configuration ---
var config = new ConfigurationBuilder()
    .AddJsonFile("appsettings.json", optional: true)
    .AddEnvironmentVariables()
    .Build();
var baseUrl = config["baseUrl"] ?? "https://api.openai.com/v1";
var apiKey = config["apiKey"] ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new Exception("No API key. Set OPENAI_API_KEY or configure appsettings.json");
var modelId = config["modelId"] ?? "gpt-4o-mini";

// --- IChatClient ---
var rawClient = new OpenAIClient(new ApiKeyCredential(apiKey), new OpenAIClientOptions { Endpoint = new Uri(baseUrl) })
    .GetChatClient(modelId).AsIChatClient();

// --- Tool definitions ---
[Description("Get the current weather for a location")]
static string GetWeather([Description("City name")] string city) =>
    city.ToLower() switch {
        "london" => "London: 15°C, cloudy",
        "tokyo" => "Tokyo: 28°C, sunny",
        _ => $"{city}: 22°C, partly cloudy"
    };

[Description("Run a shell command")]
static string RunCommand([Description("The command to execute")] string command)
{
    if (command.Contains("rm -rf", StringComparison.OrdinalIgnoreCase))
        return "BLOCKED: dangerous command refused";
    return $"Executed: {command}";
}

var tools = new List<AITool>
{
    AIFunctionFactory.Create(GetWeather),
    AIFunctionFactory.Create(RunCommand),
};

// --- Build pipeline: audit → function invocation → raw client ---
var auditClient = new AuditMiddleware(new FunctionInvokingChatClient(rawClient));

// --- Agent setup ---
var agent = new ChatClientAgent(auditClient,
    instructions: "You are a helpful assistant. Use tools when appropriate.",
    name: "assistant",
    description: "A helpful assistant",
    tools: tools);

// --- Run queries ---
var queries = new[]
{
    "What's the weather in London?",
    "Run the command 'ls -la'",
    "Run the command 'rm -rf /'",
};

foreach (var query in queries)
{
    Console.WriteLine($"\n>>> User: {query}");
    var response = await agent.RunAsync(query);
    Console.WriteLine($"<<< Agent: {response.Text}");
}

// --- Show audit log summary ---
Console.WriteLine("\n--- Audit Log ---");
foreach (var entry in auditClient.AuditLog)
    Console.WriteLine($"  {entry}");

// --- Audit middleware via DelegatingChatClient ---
sealed class AuditMiddleware(IChatClient inner) : DelegatingChatClient(inner)
{
    private readonly List<string> _auditLog = [];
    public IReadOnlyList<string> AuditLog => _auditLog;

    public override async Task<ChatResponse> GetResponseAsync(
        IEnumerable<ChatMessage> messages, ChatOptions? options = null, CancellationToken ct = default)
    {
        var msgList = messages.ToList();
        Console.WriteLine($"[HOOK] Pre-call: {msgList.Count} messages, {options?.Tools?.Count ?? 0} tools registered");

        var response = await base.GetResponseAsync(messages, options, ct);

        foreach (var content in response.Messages.SelectMany(m => m.Contents))
        {
            if (content is FunctionCallContent fcc)
            {
                var args = fcc.Arguments is not null
                    ? string.Join(", ", fcc.Arguments.Select(kv => $"{kv.Key}={kv.Value}"))
                    : "none";
                var entry = $"Tool called: {fcc.Name}({args})";
                Console.WriteLine($"[HOOK] {entry}");
                _auditLog.Add(entry);
            }
            if (content is FunctionResultContent frc)
            {
                var resultText = frc.Result?.ToString() ?? "(null)";
                if (resultText.Length > 100) resultText = resultText[..100] + "...";
                var entry = $"Tool result: {resultText}";
                Console.WriteLine($"[HOOK] {entry}");
                _auditLog.Add(entry);
            }
        }
        return response;
    }
}

using System.ClientModel;
using System.ComponentModel;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using OpenAI;

Console.OutputEncoding = System.Text.Encoding.UTF8;

// ── Config ──
var config = new ConfigurationBuilder()
    .AddJsonFile("appsettings.json", optional: true)
    .AddEnvironmentVariables()
    .Build();
var baseUrl = config["baseUrl"] ?? "https://api.openai.com/v1";
var apiKey = config["apiKey"] ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new Exception("No API key. Set OPENAI_API_KEY or configure appsettings.json");
var modelId = config["modelId"] ?? "gpt-4o-mini";

var chatClient = new OpenAIClient(new ApiKeyCredential(apiKey), new OpenAIClientOptions { Endpoint = new Uri(baseUrl) })
    .GetChatClient(modelId).AsIChatClient();

// ── Todo State ──
var todoItems = new List<TodoItem>();

// ── Todo Tool ──
[Description("Update the todo list. Provide a JSON array of items with content and status (pending, in_progress, completed).")]
string todo_write(
    [Description("JSON array of objects: [{\"content\": \"...\", \"status\": \"pending|in_progress|completed\"}]")] string items)
{
    var parsed = JsonSerializer.Deserialize<List<TodoItem>>(items, new JsonSerializerOptions { PropertyNameCaseInsensitive = true });
    if (parsed is null || parsed.Count == 0) return "No items provided.";

    // Merge by content: update existing, add new
    foreach (var item in parsed)
    {
        var existing = todoItems.FirstOrDefault(t => t.Content == item.Content);
        if (existing is not null)
            existing.Status = item.Status;
        else
            todoItems.Add(item);
    }
    return $"Todo list updated ({todoItems.Count} items). Current state:\n" +
           string.Join("\n", todoItems.Select(t => $"  [{t.Status}] {t.Content}"));
}

var tools = new List<AITool> { AIFunctionFactory.Create(todo_write) };

// ── Agent ──
var agent = new ChatClientAgent(
    new FunctionInvokingChatClient(chatClient),
    instructions: "You are a planning agent. When given a task, break it down into steps using the todo_write tool. " +
                  "Mark items as in_progress when working on them, completed when done. Always plan before acting.",
    name: "planner",
    description: "An agent that plans tasks using a todo list",
    tools: tools);

// ── Run ──
Console.WriteLine("s07: Planning via TodoWrite — break tasks into tracked steps\n");
var response = await agent.RunAsync("Plan the steps to build a simple REST API with a health endpoint and a users CRUD endpoint. Use todo_write to track your plan.");
Console.WriteLine($"Agent: {response.Text}");

Console.WriteLine("\n── Final Todo State ──");
foreach (var item in todoItems)
    Console.WriteLine($"  [{item.Status}] {item.Content}");

// ── Model ──
record TodoItem
{
    public string Content { get; set; } = "";
    public string Status { get; set; } = "pending";
}

using System.ClientModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using OpenAI;

Console.OutputEncoding = System.Text.Encoding.UTF8;

// ── Config ──
var config = new ConfigurationBuilder()
    .AddJsonFile("appsettings.json", optional: true)
    .AddEnvironmentVariables()
    .Build();
var baseUrl = config["baseUrl"] ?? "https://api.openai.com/v1";
var apiKey = config["apiKey"] ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? throw new Exception("No API key. Set OPENAI_API_KEY or configure appsettings.json");
var modelId = config["modelId"] ?? "gpt-4o-mini";

var chatClient = new OpenAIClient(new ApiKeyCredential(apiKey), new OpenAIClientOptions { Endpoint = new Uri(baseUrl) })
    .GetChatClient(modelId).AsIChatClient();

// ── Specialist Agents ──
AIAgent researcher = chatClient.AsAIAgent(
    instructions: "You are a research specialist. Given a topic, provide key facts, recent developments, and important context. Be thorough but concise.",
    name: "researcher",
    description: "Researches topics and gathers information");

AIAgent writer = chatClient.AsAIAgent(
    instructions: "You are a writing specialist. Given research notes, compose a clear, engaging summary suitable for a general audience.",
    name: "writer",
    description: "Writes summaries from research notes");

// ── Convert agents to tools ──
var tools = new List<AITool>
{
    researcher.AsAIFunction(),
    writer.AsAIFunction(),
};

// ── Coordinator Agent ──
var coordinator = new ChatClientAgent(chatClient,
    instructions: "You are a coordinator that delegates to specialist agents. " +
                  "Use the researcher tool to gather information, then use the writer tool to compose a summary. " +
                  "Always use both tools in sequence: research first, then write.",
    name: "coordinator",
    description: "Coordinates research and writing tasks",
    tools: tools);

// ── Run ──
Console.WriteLine("s08: Agent as Tool — specialist agents composed under a coordinator\n");
var response = await coordinator.RunAsync("Research the current state of quantum computing in 2025 and write a short summary about it.");
Console.WriteLine(response.Text);

using System.ClientModel;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Configuration;
using OpenAI;

Console.OutputEncoding = System.Text.Encoding.UTF8;

// ── Config ──
var config = new ConfigurationBuilder()
    .AddJsonFile("appsettings.json", optional: true)
    .AddEnvironmentVariables()
    .Build();
var baseUrl = config["baseUrl"] ?? "https://api.openai.com/v1";
