{
    Console.WriteLine($"  [{DateTime.Now:HH:mm:ss}] Checking...");
    foreach (var id in backgroundTasks.Keys)
        Console.WriteLine($"    {CheckTask(id)}");
    await Task.Delay(1000);
}
