    city.ToLower() switch
    {
        "london" => "London: 15°C, cloudy",
        "tokyo" => "Tokyo: 28°C, sunny",
        _ => $"{city}: 22°C, partly cloudy"
    };

[Description("Run a shell command")]
static string RunBash([Description("Command to execute")] string command) =>
    $"Executed: {command}";

var tools = new List<AITool>
{
